const fs = require('fs');
const dmPath = '/tmp/lead_dms.json';

let dms = [];
try { dms = JSON.parse(fs.readFileSync(dmPath, 'utf8')); } catch(e) {}

// Find initial DMs sent >48h ago that haven't been followed up
const now = Date.now();
const followedUp = new Set(dms.filter(d => d.type === 'followup').map(d => d.business));

const due = dms.filter(d => {
  if (d.type !== 'initial') return false;
  if (followedUp.has(d.business)) return false;
  const sentAt = new Date(d.sent_at).getTime();
  return (now - sentAt) > 48 * 60 * 60 * 1000; // 48h
});

if (due.length === 0) {
  return { ready: false, message: 'No follow-ups due' };
}

// Take first due
const lead = due[0];
const first = (lead.business || '').split(' ')[0] || lead.business;

// Follow-up templates
const fuTemplates = [
  { subject: 'Re: Quick question for {first}', body: 'Hi {first},\n\nJust circling back — my last email probably got buried.\n\nI help {industry} business owners save 15-20 hrs/week on admin. No fluff, just a dedicated assistant.\n\nIf that sounds useful, reply and we can hop on a quick call.\n\nBest,\nAyan' },
  { subject: 'Following up, {first}', body: 'Hi {first},\n\nNot trying to be pushy — genuinely curious if admin overload is something you deal with.\n\nMost {industry} owners I talk to say they lose 10+ hrs/week on emails, scheduling, and follow-ups.\n\nWant to chat for 10 min this week?\n\nBest,\nAyan' }
];

const tpl = fuTemplates[Math.floor(Math.random() * fuTemplates.length)];
const subject = tpl.subject.replace('{first}', first);
const body = tpl.body.replace('{first}', first).replace(/{industry}/g, lead.industry || 'your industry');

return {
  ready: true,
  business: lead.business,
  email: lead.email,
  first_name: first,
  subject,
  body,
  industry: lead.industry || 'general'
};

const fs = require('fs');
const dmPath = '/tmp/lead_dms.json';

let dms = [];
try { dms = JSON.parse(fs.readFileSync(dmPath, 'utf8')); } catch(e) {}

dms.push({
  business: $json.business,
  email: $json.email,
  subject: $json.subject,
  type: 'followup',
  sent_at: new Date().toISOString()
});

if (dms.length > 500) dms = dms.slice(-500);
fs.writeFileSync(dmPath, JSON.stringify(dms, null, 2));

return {
  status: 'followup_sent',
  business: $json.business,
  email: $json.email
};
